SELECT t."team_long_name", c."total_wins" FROM (SELECT "team_api_id", SUM("wins") AS "total_wins" FROM (SELECT "home_team_api_id" AS "team_api_id", COUNT(*) AS "wins" FROM "EU_SOCCER"."EU_SOCCER"."MATCH" WHERE "home_team_goal" > "away_team_goal" GROUP BY "home_team_api_id" UNION ALL SELECT "away_team_api_id" AS "team_api_id", COUNT(*) AS "wins" FROM "EU_SOCCER"."EU_SOCCER"."MATCH" WHERE "away_team_goal" > "home_team_goal" GROUP BY "away_team_api_id") GROUP BY "team_api_id") c JOIN "EU_SOCCER"."EU_SOCCER"."TEAM" t ON c."team_api_id" = t."team_api_id" ORDER BY c."total_wins" DESC LIMIT 10